      "content": "const express = require('express');
const router = express.Router({ mergeParams: true }); // Use relative paths for nested routes
const { getTasksByStatus, updateTaskStatus } = require('./service');

router.get('/', getTasksByStatus); // Add task filtering contract
router.patch('/:taskId', (req, res) => {
  const status = req.body.status;
  if (!['todo', 'done'].includes(status)) return sendError(res, 400, 'InvalidStatus', 'Status must be todo or done');
  updateTaskStatus(req.params.taskId, status).then((updatedTask) => {
    if (updatedTask) res.json({ task: updatedTask });
    else sendError(res, 404, 'NotFound', 'Task not found');
  }).catch(() => sendError(res, 500, 'InternalServerError', 'An error occurred while updating the task status'));
});

module.exports = router;
